#include<bits/stdc++.h>using namespace std;int q,n,ans=0;string s,t;bool check(string s){	for(int i=0;i<s.size();i++){		if(s[i]!=t[i]) return false;	}	return true;}int main(){	cin>>q;	while(q--){		cin>>s>>t;		int f=0;		for(int i=0;i<s.size();i++){			for(int x=0;x<=s.size()-i-1;x++){				int y=t.length()-x-1;				if(y>i+x) continue;				string h="";				for(int j=i,k=0;k<=x;j++,k++) h=h+s[j];				for(int j=i+x-1,k=1;k<=y;j--,k++) h=h+s[j];				if(check(h)) f=1;			}		}		if(f==1) cout<<"YES"<<endl;		else cout<<"NO"<<endl;	}		return 0;}